            this.location = _data["location"];
            this.status = _data["status"];
            if (Array.isArray(_data["deltagare"])) {
                this.deltagare = [] as any;
                for (let item of _data["deltagare"])
                    this.deltagare!.push(StudentDto.fromJS(item));
            }
